const { DateTime } = require('luxon');
const now = DateTime.now().setZone('America/Sao_Paulo');
const pad = (n) => String(n).padStart(2, '0');

const nomes = ['domingo', 'segunda', 'terça', 'quarta', 'quinta', 'sexta', 'sábado'];

let result = `Hoje é ${nomes[now.weekday % 7]} ${pad(now.day)}/${pad(now.month)}/${String(now.year).slice(2)} às ${pad(now.hour)}:${pad(now.minute)}\n`;

for (let i = 1; i <= 6; i++) {
  const future = now.plus({ days: i });
  const dia = pad(future.day);
  const mes = pad(future.month);
  const ano = String(future.year).slice(2);
  const nomeDia = nomes[future.weekday % 7];

  let label = '';
  if (i === 1) {
    label = `Amanhã é ${nomeDia} ${dia}/${mes}/${ano}`;
  } else if (i === 2) {
    label = `Depois de amanhã é ${nomeDia} ${dia}/${mes}/${ano}`;
  } else {
    label = `A próxima ${nomeDia} será dia ${dia}/${mes}/${ano}`;
  }
  result += `${label}\n`;
}

return [{ json: { resultado: result.trim() } }];

